#include <stdio.h>
#include <string.h>
#include <arpa/inet.h>
#include <netinet/in.h>

typedef struct {
    struct sockaddr_in src;
    struct sockaddr_in dst;
    char payload[64];
} NetMsg;

/* == EXEMPLE ===============================================
 * Datagramme reponse : inverser src/dst avec payload "pong"
 * NetMsg regroupe adresses source, destination et donnees.
 * ========================================================= */
void example_response_msg(void) {
    NetMsg resp;
    memset(&resp, 0, sizeof(resp));
    resp.src.sin_family = AF_INET;
    resp.src.sin_port = htons(5678);
    inet_pton(AF_INET, "10.0.0.2", &resp.src.sin_addr);
    resp.dst.sin_family = AF_INET;
    resp.dst.sin_port = htons(1234);
    inet_pton(AF_INET, "10.0.0.1", &resp.dst.sin_addr);
    strncpy(resp.payload, "pong", sizeof(resp.payload) - 1);
    char s[INET_ADDRSTRLEN], d[INET_ADDRSTRLEN];
    inet_ntop(AF_INET, &resp.src.sin_addr, s, sizeof(s));
    inet_ntop(AF_INET, &resp.dst.sin_addr, d, sizeof(d));
    printf("Reply: %s:%d -> %s:%d [%s]\n",
           s, ntohs(resp.src.sin_port), d, ntohs(resp.dst.sin_port), resp.payload);
}
/* Resultat: Reply: 10.0.0.2:5678 -> 10.0.0.1:1234 [pong] */

